import{_ as n,o as t,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F10: 成本結構與經營槓桿門檻","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F10_成本結構與經營槓桿門檻_財務分析專家.md","filePath":"32Ｑ題本＿重要/財務組/F10_成本結構與經營槓桿門檻_財務分析專家.md"}'),r={name:"32Ｑ題本＿重要/財務組/F10_成本結構與經營槓桿門檻_財務分析專家.md"};function a(s,o,e,g,c,_){return t(),l("div",null,[...o[0]||(o[0]=[i('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f10-成本結構與經營槓桿門檻" tabindex="-1">F10: 成本結構與經營槓桿門檻 <a class="header-anchor" href="#f10-成本結構與經營槓桿門檻" aria-label="Permalink to &quot;F10: 成本結構與經營槓桿門檻&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F10</li><li><strong>題目：</strong> 公司的成本結構為何？固定成本與變動成本的比例如何影響其規模經濟？企業目前的「獲利擴張臨界點」在那裡？</li><li><strong>推薦專家：</strong> 財務分析師 (<code>finance-financial-analyst</code>)</li><li><strong>推薦理由：</strong> 專精於「管理會計」與「邊際獲利模型」。具備測算企業「盈虧平衡點 (Breakeven)」與「經營槓桿係數 (DOL)」之能力。財務分析師的核心價值在於識別企業獲利的「彈性」與「脆弱性」，判定營收變動對淨利的非線性放大量級。</li><li><strong>意圖：</strong> 執行「成本習性與規模經濟審計」，掌握公司營運的「生存成本門檻」，識別其在營收回升期是否具備「獲利倍數暴發」的槓桿特質。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心事實來源：Annual Report (年報)】</strong>：必須查閱「財務報告附註 -&gt; 營業費用依性質分類」章節。獲取年度「折舊費用」、「攤銷費用」與「員工福利支出」之具體數額。</li><li><strong>【外部事實確認：FinMind】</strong>：調用 <code>TaiwanStockFinancialStatements</code> 提取歷年「營業成本」與「營業費用」。</li><li><strong>【穿透校準：Google Search】</strong>：檢索「[公司名] 擴產 資本支出」、「[公司名] 自動化 比例」、「[公司名] 裁員 成本優化」。</li></ol></li><li><strong>邏輯：</strong> 執行「經營槓桿係數 (DOL) 算則」——分析固定成本 (Fixed Cost) 佔總營運支出的比重；評估產能利用率每上升 10% 對營業利益率 (OPM) 的實質邊際貢換。</li><li><strong>來源：</strong> <code>FinMind</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>跑工具</strong>：<code>python3 財務分析工具.py cost_structure [股號]</code> → 取得 COGS、OPEX 佔比</li><li><strong>取年報</strong>：用 <code>pdf</code> 工具從年報提取「營業費用明細」（折舊、薪資）估算固定/變動成本</li><li><strong>計算 DOL</strong>：(營收 - 變動成本) / (營收 - 變動成本 - 固定成本)</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><p>⚠️ <strong>常見陷阱</strong>：①專家評析 ≥200 字；②空頭視角 ≥2 個；③DOL 要直接算出數字</p><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【成本事實優先】</strong>：智慧體<strong>必須</strong>列出最近 2 年的「固定成本項 (折舊+攤銷+核心薪資)」佔營收之百分比。禁止在未明列固定負擔前進行規模經濟優勢判定。</li><li><strong>【槓桿臨界偵測】</strong>：智慧體必須估算目前的「產能利用率」。若利用率低於 70% 且折舊年增率 &gt; 20%，必須強制發出「高經營槓桿、毛利稀釋」警訊。</li><li><strong>【損益平衡分析】</strong>：分析營收每下降 10% 對淨利的衝擊。若淨利跌幅 &gt; 30%，標註為「高敏感度企業」，需警惕景氣下行時的爆雷風險。</li><li><strong>【Ticker 校準】</strong>：使用 yfinance 時，必須遵循 <code>.TW</code> (上市) 或 <code>.TWO</code> (上櫃) 規範，嚴禁輸入純數字。</li><li><strong>【描述指標】</strong>：絕對禁用「獲利爆發力強」、「成本控制穩健」。必須量化為具體的「固定資產佔比 %」、「營業槓桿係數估值」與「剩餘閒置產能 %」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f10-專家答詢】財務分析師-finance-financial-analyst" tabindex="-1">【F10 專家答詢】財務分析師 (finance-financial-analyst) <a class="header-anchor" href="#【f10-專家答詢】財務分析師-finance-financial-analyst" aria-label="Permalink to &quot;【F10 專家答詢】財務分析師 (finance-financial-analyst)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「槓桿特徵+脆弱性判定」結構（例：固定成本佔比 X% (屬 [高/低] 槓桿)，產能利用率 Y%，獲利彈性為 [爆發型/穩健型]，生存壓力點位於營營收 Z 億元處）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：具備優異的規模經濟效率，固定成本已被營收超額覆蓋，每增加一單位營收幾乎全數轉化為邊際毛利，展現強大的獲利爆發特徵。</li><li><strong>A (良)</strong>：成本結構平衡，變動成本佔比較高，賦予公司在景氣下行時強大的防禦與裁撤彈性，獲利質量穩定。</li><li><strong>B (持平)</strong>：陷入「資本重載陷阱」——固定成本極高且產能利用率長期低於 65%，陷入「做一單賠一單」的折舊黑洞，面臨嚴重的流動性枯竭風險。</li></ul></li><li><strong>【答詢詳解】解析深度</strong>：依照以下三個維度回答： <ol><li><strong>營運成本習性拆解 (Cost Behavior Analysis)</strong>：區分原物料 (變動) 與設備/人工 (固定) 的博弈關係。</li><li><strong>規模經濟臨界檢核 (Scalability Threshold)</strong>：推算公司需跨過多少營收水位才能啟動「獲利加速器」。</li><li><strong>景氣承壓測試 (Cyclical Stress Test)</strong>：模擬在需求萎縮 20% 的極端情境下，經營槓桿對獲利侵蝕的倍率。</li></ol></li><li><strong>【證據來源】數據溯源</strong>：必須精確標註年報附註 P.XXX 費用性質分類表。</li><li><strong>【專家評析】核心分析與洞察內容</strong>：特別關注「折舊年限的變動」。若公司在營收下行時突然拉長折舊年限，專家應在此處診斷為「財務粉飾」。判定這是「擴張的跳板 (Expansion Trampoline)」還是「沈重的枷鎖 (Heavy Shackles)」。</li></ul>',12)])])}const f=n(r,[["render",a]]);export{h as __pageData,f as default};
